(function(){'use strict';
const SLUG="privacy-policy";
const NAMESPACE="StatKISS_I18N_PRIVACY_POLICY";
const SUPPORTED_LANGS=["en","ko","ja","zh-Hans","zh-Hant","es","fr","de","pt-BR","ru","id","vi","th","ms","fil","hi","ar","it","nl","pl","sv","tr","uk"];
const DOCUMENTS={"en":{"slug":"privacy-policy","document_title":"Privacy Policy","document_summary":"How StatKISS collects, uses, shares, retains, and protects personal information.","document_sections":[{"heading":"Purpose and scope","body_html":"<p>This policy explains how StatKISS, operated for the Korean International Statistical Society (KISS), handles personal information from members, authors, reviewers, donors, event participants, and visitors.</p>","article_title":"ARTICLE 1. Purpose and scope"},{"heading":"Data we collect","body_html":"<p>We may collect account and profile data such as name, email, affiliation, title, membership selections, event registrations, uploaded files, and communication preferences. We may also collect technical data such as session records, IP-based security logs, device or browser metadata, and page visit information.</p>","article_title":"ARTICLE 2. Data we collect"},{"heading":"Use, sharing, and international transfers","body_html":"<p>We use information to authenticate users, operate memberships and events, manage publications and announcements, respond to requests, prevent abuse, and improve platform security and reliability. We do not sell personal information, but we may share it with service providers that support hosting, authentication, email delivery, payments, storage, or legal compliance, and information may be processed across jurisdictions used by an international scholarly society.</p>","article_title":"ARTICLE 3. Use, sharing, and international transfers"},{"heading":"Retention, security, and your choices","body_html":"<p>We keep information only as long as reasonably necessary for service operation, legal obligations, accounting, dispute handling, and security review. You may request profile corrections or ask privacy questions at <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>, and although StatKISS applies reasonable safeguards, no internet service can guarantee absolute security.</p>","article_title":"ARTICLE 4. Retention, security, and your choices"}],"effective_date_label":"Effective date","last_updated_label":"Last updated","effective_date":"2026-03-28","last_updated":"2026-03-28"},"ko":{"slug":"privacy-policy","document_title":"개인정보처리방침","document_summary":"StatKISS가 개인정보를 어떻게 수집·이용·공유·보관·보호하는지 설명합니다.","document_sections":[{"heading":"목적과 적용 범위","body_html":"<p>이 방침은 대한국제통계학회(KISS)를 위해 운영되는 StatKISS가 회원, 저자, 심사자, 후원자, 행사 참가자, 방문자의 개인정보를 어떻게 처리하는지 설명합니다.</p>","article_title":"제1조. 목적과 적용 범위"},{"heading":"수집하는 정보","body_html":"<p>당사는 이름, 이메일, 소속, 직함, 회원 선택 정보, 행사 등록 정보, 업로드 파일, 수신 동의와 같은 계정·프로필 정보를 수집할 수 있습니다. 또한 세션 기록, IP 기반 보안 로그, 기기·브라우저 메타데이터, 페이지 방문 정보와 같은 기술 정보도 수집할 수 있습니다.</p>","article_title":"제2조. 수집하는 정보"},{"heading":"이용, 공유 및 국외 처리","body_html":"<p>당사는 사용자 인증, 회원·행사 운영, 출판물·공지 관리, 문의 대응, 오남용 방지, 플랫폼 보안과 안정성 개선을 위해 정보를 이용합니다. 개인정보를 판매하지는 않지만, 호스팅, 인증, 이메일 발송, 결제, 저장소, 법적 준수를 지원하는 서비스 제공자와 필요한 범위에서 공유할 수 있으며, 국제 학술단체 운영 특성상 여러 국가에서 처리될 수 있습니다.</p>","article_title":"제3조. 이용, 공유 및 국외 처리"},{"heading":"보관, 보안 및 이용자 선택","body_html":"<p>당사는 서비스 운영, 법적 의무, 회계, 분쟁 처리, 보안 점검에 필요한 기간 동안만 정보를 보관합니다. 개인정보 정정 요청이나 개인정보 관련 문의는 <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>로 보내실 수 있으며, StatKISS는 합리적인 보호조치를 적용하지만 어떤 인터넷 서비스도 절대적 보안을 보장할 수는 없습니다.</p>","article_title":"제4조. 보관, 보안 및 이용자 선택"}],"effective_date_label":"시행일","last_updated_label":"최종 업데이트","effective_date":"2026-03-28","last_updated":"2026-03-28"},"ja":{"slug":"privacy-policy","document_title":"プライバシーポリシー","document_summary":"StatKISSが個人情報をどのように収集、利用、共有、保存、保護するかを説明します。","document_sections":[{"heading":"目的と適用範囲","body_html":"<p>本ポリシーは、韓国国際統計学会（KISS）のために運営されるStatKISSが、会員、著者、査読者、寄付者、イベント参加者、訪問者の個人情報をどのように取り扱うかを説明するものです。</p>","article_title":"第1条. 目的と適用範囲"},{"heading":"収集する情報","body_html":"<p>当サイトは、氏名、メールアドレス、所属、役職、会員区分、イベント登録情報、アップロードされたファイル、連絡設定などのアカウント・プロフィール情報を収集する場合があります。また、セッション記録、IPベースのセキュリティログ、端末やブラウザのメタデータ、ページ閲覧情報などの技術情報も収集する場合があります。</p>","article_title":"第2条. 収集する情報"},{"heading":"利用、共有、および国際移転","body_html":"<p>当サイトは、利用者認証、会員・イベント運営、出版物や告知の管理、お問い合わせ対応、不正防止、プラットフォームの安全性と信頼性向上のために情報を利用します。個人情報を販売することはありませんが、ホスティング、認証、メール送信、決済、保存、法令対応を支援する提供事業者と必要な範囲で共有する場合があり、国際的な学術団体の運営上、複数の国で処理されることがあります。</p>","article_title":"第3条. 利用、共有、および国際移転"},{"heading":"保存、セキュリティ、および利用者の選択","body_html":"<p>当サイトは、サービス運営、法的義務、会計、紛争対応、セキュリティ確認に必要な期間に限って情報を保持します。プロフィールの訂正依頼やプライバシーに関するお問い合わせは <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a> までご連絡ください。StatKISSは合理的な保護措置を講じますが、いかなるインターネットサービスも絶対的な安全性を保証することはできません。</p>","article_title":"第4条. 保存、セキュリティ、および利用者の選択"}],"effective_date_label":"施行日","last_updated_label":"最終更新","effective_date":"2026-03-28","last_updated":"2026-03-28"},"zh-Hans":{"slug":"privacy-policy","document_title":"隐私政策","document_summary":"说明 StatKISS 如何收集、使用、共享、保存和保护个人信息。","document_sections":[{"heading":"目的与适用范围","body_html":"<p>本政策说明为韩国国际统计学会（KISS）运营的 StatKISS 如何处理会员、作者、审稿人、捐赠者、活动参与者和访客的个人信息。</p>","article_title":"第1条. 目的与适用范围"},{"heading":"我们收集的数据","body_html":"<p>我们可能收集姓名、电子邮箱、所属机构、职务、会员选择、活动报名信息、上传文件和通信偏好等账户与个人资料信息。我们也可能收集会话记录、基于 IP 的安全日志、设备或浏览器元数据以及页面访问信息等技术数据。</p>","article_title":"第2条. 我们收集的数据"},{"heading":"使用、共享与跨境处理","body_html":"<p>我们使用这些信息来验证用户身份、运营会员与活动、管理出版物和公告、回应请求、防止滥用，并提升平台的安全性和可靠性。我们不会出售个人信息，但在提供托管、认证、邮件发送、支付、存储或法律合规支持时，可能会向相关服务提供商披露必要信息；作为国际学术团体的一部分，信息也可能在多个司法辖区中处理。</p>","article_title":"第3条. 使用、共享与跨境处理"},{"heading":"保存、安全与您的选择","body_html":"<p>我们仅在服务运营、法律义务、会计、争议处理和安全审查所合理需要的期限内保存信息。您可以通过 <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a> 申请更正个人资料或提出隐私相关问题。StatKISS 会采取合理的保护措施，但任何互联网服务都无法保证绝对安全。</p>","article_title":"第4条. 保存、安全与您的选择"}],"effective_date_label":"生效日期","last_updated_label":"最后更新","effective_date":"2026-03-28","last_updated":"2026-03-28"},"zh-Hant":{"slug":"privacy-policy","document_title":"隱私政策","document_summary":"說明 StatKISS 如何蒐集、使用、分享、保存與保護個人資料。","document_sections":[{"heading":"目的與適用範圍","body_html":"<p>本政策說明為韓國國際統計學會（KISS）營運的 StatKISS 如何處理會員、作者、審稿人、捐助者、活動參與者與訪客的個人資料。</p>","article_title":"第1條. 目的與適用範圍"},{"heading":"我們蒐集的資料","body_html":"<p>我們可能蒐集姓名、電子郵件、所屬機構、職稱、會員選擇、活動報名資訊、上傳檔案與通訊偏好等帳號與個人檔案資料。我們也可能蒐集工作階段紀錄、基於 IP 的安全日誌、裝置或瀏覽器中繼資料，以及頁面瀏覽資訊等技術資料。</p>","article_title":"第2條. 我們蒐集的資料"},{"heading":"使用、分享與跨境處理","body_html":"<p>我們使用這些資訊來驗證使用者身分、營運會員與活動、管理出版物與公告、回應請求、防止濫用，並提升平台的安全性與可靠性。我們不出售個人資料，但在提供主機、驗證、電子郵件寄送、支付、儲存或法令遵循支援時，可能會向相關服務提供者揭露必要資訊；作為國際學術團體的一部分，資訊也可能在多個司法管轄區中處理。</p>","article_title":"第3條. 使用、分享與跨境處理"},{"heading":"保存、安全與您的選擇","body_html":"<p>我們僅在服務營運、法律義務、會計、爭議處理與安全審查所合理需要的期間內保存資訊。您可以透過 <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a> 要求更正個人資料或提出隱私相關問題。StatKISS 會採取合理的保護措施，但任何網際網路服務都無法保證絕對安全。</p>","article_title":"第4條. 保存、安全與您的選擇"}],"effective_date_label":"生效日期","last_updated_label":"最後更新","effective_date":"2026-03-28","last_updated":"2026-03-28"},"es":{"slug":"privacy-policy","document_title":"Política de privacidad","document_summary":"Explica cómo StatKISS recopila, utiliza, comparte, conserva y protege la información personal.","document_sections":[{"heading":"Finalidad y alcance","body_html":"<p>Esta política explica cómo StatKISS, operado para la Korean International Statistical Society (KISS), trata la información personal de miembros, autores, revisores, donantes, participantes en eventos y visitantes.</p>","article_title":"ARTÍCULO 1. Finalidad y alcance"},{"heading":"Datos que recopilamos","body_html":"<p>Podemos recopilar datos de cuenta y perfil como nombre, correo electrónico, afiliación, cargo, opciones de membresía, inscripciones a eventos, archivos cargados y preferencias de comunicación. También podemos recopilar datos técnicos como registros de sesión, bitácoras de seguridad basadas en IP, metadatos del dispositivo o navegador e información de visitas a páginas.</p>","article_title":"ARTÍCULO 2. Datos que recopilamos"},{"heading":"Uso, intercambio y transferencias internacionales","body_html":"<p>Utilizamos la información para autenticar usuarios, operar membresías y eventos, gestionar publicaciones y anuncios, responder solicitudes, prevenir abusos y mejorar la seguridad y confiabilidad de la plataforma. No vendemos información personal, pero podemos compartirla con proveedores que apoyan el alojamiento, la autenticación, el envío de correo, los pagos, el almacenamiento o el cumplimiento legal, y la información puede procesarse en varias jurisdicciones utilizadas por una sociedad académica internacional.</p>","article_title":"ARTÍCULO 3. Uso, intercambio y transferencias internacionales"},{"heading":"Conservación, seguridad y sus opciones","body_html":"<p>Conservamos la información solo durante el tiempo razonablemente necesario para la operación del servicio, obligaciones legales, contabilidad, resolución de disputas y revisión de seguridad. Puede solicitar correcciones de perfil o hacer consultas de privacidad a <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Aunque StatKISS aplica salvaguardas razonables, ningún servicio en internet puede garantizar seguridad absoluta.</p>","article_title":"ARTÍCULO 4. Conservación, seguridad y sus opciones"}],"effective_date_label":"Fecha de entrada en vigor","last_updated_label":"Última actualización","effective_date":"2026-03-28","last_updated":"2026-03-28"},"fr":{"slug":"privacy-policy","document_title":"Politique de confidentialité","document_summary":"Explique comment StatKISS collecte, utilise, partage, conserve et protège les informations personnelles.","document_sections":[{"heading":"Objet et champ d’application","body_html":"<p>Cette politique explique comment StatKISS, exploité pour la Korean International Statistical Society (KISS), traite les informations personnelles des membres, auteurs, évaluateurs, donateurs, participants aux événements et visiteurs.</p>","article_title":"ARTICLE 1. Objet et champ d’application"},{"heading":"Données que nous collectons","body_html":"<p>Nous pouvons collecter des données de compte et de profil telles que le nom, l’adresse e-mail, l’affiliation, la fonction, les choix de membership, les inscriptions aux événements, les fichiers téléversés et les préférences de communication. Nous pouvons également collecter des données techniques telles que les enregistrements de session, les journaux de sécurité liés à l’IP, les métadonnées de l’appareil ou du navigateur et les informations de visite des pages.</p>","article_title":"ARTICLE 2. Données que nous collectons"},{"heading":"Utilisation, partage et transferts internationaux","body_html":"<p>Nous utilisons ces informations pour authentifier les utilisateurs, gérer les adhésions et les événements, administrer les publications et annonces, répondre aux demandes, prévenir les abus et améliorer la sécurité et la fiabilité de la plateforme. Nous ne vendons pas d’informations personnelles, mais nous pouvons les partager avec des prestataires qui assurent l’hébergement, l’authentification, l’envoi d’e-mails, les paiements, le stockage ou la conformité légale, et les informations peuvent être traitées dans plusieurs juridictions utilisées par une société savante internationale.</p>","article_title":"ARTICLE 3. Utilisation, partage et transferts internationaux"},{"heading":"Conservation, sécurité et vos choix","body_html":"<p>Nous conservons les informations uniquement pendant la durée raisonnablement nécessaire au fonctionnement du service, aux obligations légales, à la comptabilité, au traitement des litiges et aux contrôles de sécurité. Vous pouvez demander la correction de votre profil ou poser des questions relatives à la confidentialité à <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Bien que StatKISS applique des mesures de protection raisonnables, aucun service internet ne peut garantir une sécurité absolue.</p>","article_title":"ARTICLE 4. Conservation, sécurité et vos choix"}],"effective_date_label":"Date d’entrée en vigueur","last_updated_label":"Dernière mise à jour","effective_date":"2026-03-28","last_updated":"2026-03-28"},"de":{"slug":"privacy-policy","document_title":"Datenschutzerklärung","document_summary":"Erläutert, wie StatKISS personenbezogene Daten erhebt, nutzt, weitergibt, speichert und schützt.","document_sections":[{"heading":"Zweck und Geltungsbereich","body_html":"<p>Diese Erklärung erläutert, wie StatKISS, das für die Korean International Statistical Society (KISS) betrieben wird, personenbezogene Daten von Mitgliedern, Autorinnen und Autoren, Gutachtenden, Spendern, Veranstaltungsteilnehmenden und Besuchenden verarbeitet.</p>","article_title":"ARTIKEL 1. Zweck und Geltungsbereich"},{"heading":"Welche Daten wir erheben","body_html":"<p>Wir können Konto- und Profildaten wie Name, E-Mail-Adresse, Zugehörigkeit, Position, Mitgliedschaftsauswahl, Veranstaltungsanmeldungen, hochgeladene Dateien und Kommunikationseinstellungen erheben. Außerdem können wir technische Daten wie Sitzungsprotokolle, IP-basierte Sicherheitslogs, Geräte- oder Browser-Metadaten und Seitenaufrufinformationen erfassen.</p>","article_title":"ARTIKEL 2. Welche Daten wir erheben"},{"heading":"Nutzung, Weitergabe und internationale Übermittlungen","body_html":"<p>Wir nutzen Informationen, um Nutzer zu authentifizieren, Mitgliedschaften und Veranstaltungen zu betreiben, Publikationen und Ankündigungen zu verwalten, Anfragen zu beantworten, Missbrauch zu verhindern und die Sicherheit und Zuverlässigkeit der Plattform zu verbessern. Wir verkaufen keine personenbezogenen Daten, können sie jedoch an Dienstleister weitergeben, die Hosting, Authentifizierung, E-Mail-Versand, Zahlungen, Speicherung oder rechtliche Compliance unterstützen; Informationen können außerdem in mehreren Rechtsräumen einer internationalen wissenschaftlichen Gesellschaft verarbeitet werden.</p>","article_title":"ARTIKEL 3. Nutzung, Weitergabe und internationale Übermittlungen"},{"heading":"Speicherung, Sicherheit und Ihre Wahlmöglichkeiten","body_html":"<p>Wir speichern Informationen nur so lange, wie es für den Betrieb des Dienstes, gesetzliche Pflichten, Buchhaltung, Streitbeilegung und Sicherheitsprüfungen vernünftigerweise erforderlich ist. Sie können Profilkorrekturen anfordern oder Datenschutzfragen an <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a> richten. Obwohl StatKISS angemessene Schutzmaßnahmen anwendet, kann kein Internetdienst absolute Sicherheit garantieren.</p>","article_title":"ARTIKEL 4. Speicherung, Sicherheit und Ihre Wahlmöglichkeiten"}],"effective_date_label":"Datum des Inkrafttretens","last_updated_label":"Zuletzt aktualisiert","effective_date":"2026-03-28","last_updated":"2026-03-28"},"pt-BR":{"slug":"privacy-policy","document_title":"Política de Privacidade","document_summary":"Explica como a StatKISS coleta, usa, compartilha, retém e protege informações pessoais.","document_sections":[{"heading":"Finalidade e escopo","body_html":"<p>Esta política explica como a StatKISS, operada para a Korean International Statistical Society (KISS), trata informações pessoais de membros, autores, pareceristas, doadores, participantes de eventos e visitantes.</p>","article_title":"ARTIGO 1. Finalidade e escopo"},{"heading":"Dados que coletamos","body_html":"<p>Podemos coletar dados de conta e perfil, como nome, e-mail, afiliação, cargo, escolhas de associação, inscrições em eventos, arquivos enviados e preferências de comunicação. Também podemos coletar dados técnicos, como registros de sessão, logs de segurança baseados em IP, metadados de dispositivo ou navegador e informações de visita a páginas.</p>","article_title":"ARTIGO 2. Dados que coletamos"},{"heading":"Uso, compartilhamento e transferências internacionais","body_html":"<p>Usamos as informações para autenticar usuários, operar associações e eventos, administrar publicações e anúncios, responder a solicitações, prevenir abusos e melhorar a segurança e a confiabilidade da plataforma. Não vendemos informações pessoais, mas podemos compartilhá-las com prestadores que apoiam hospedagem, autenticação, envio de e-mails, pagamentos, armazenamento ou conformidade legal, e as informações podem ser processadas em várias jurisdições usadas por uma sociedade acadêmica internacional.</p>","article_title":"ARTIGO 3. Uso, compartilhamento e transferências internacionais"},{"heading":"Retenção, segurança e suas escolhas","body_html":"<p>Mantemos as informações apenas pelo tempo razoavelmente necessário para a operação do serviço, obrigações legais, contabilidade, tratamento de disputas e revisão de segurança. Você pode solicitar correções de perfil ou enviar perguntas sobre privacidade para <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Embora a StatKISS aplique salvaguardas razoáveis, nenhum serviço de internet pode garantir segurança absoluta.</p>","article_title":"ARTIGO 4. Retenção, segurança e suas escolhas"}],"effective_date_label":"Data de vigência","last_updated_label":"Última atualização","effective_date":"2026-03-28","last_updated":"2026-03-28"},"ru":{"slug":"privacy-policy","document_title":"Политика конфиденциальности","document_summary":"Объясняет, как StatKISS собирает, использует, передает, хранит и защищает персональные данные.","document_sections":[{"heading":"Цель и сфера действия","body_html":"<p>Настоящая политика объясняет, как StatKISS, действующий для Korean International Statistical Society (KISS), обрабатывает персональные данные членов общества, авторов, рецензентов, жертвователей, участников мероприятий и посетителей.</p>","article_title":"СТАТЬЯ 1. Цель и сфера действия"},{"heading":"Какие данные мы собираем","body_html":"<p>Мы можем собирать данные учетной записи и профиля, такие как имя, адрес электронной почты, организация, должность, выбор членства, регистрация на мероприятия, загруженные файлы и предпочтения в коммуникации. Мы также можем собирать технические данные, включая записи сессий, журналы безопасности на основе IP, метаданные устройства или браузера и сведения о посещении страниц.</p>","article_title":"СТАТЬЯ 2. Какие данные мы собираем"},{"heading":"Использование, передача и международная обработка","body_html":"<p>Мы используем информацию для аутентификации пользователей, управления членством и мероприятиями, администрирования публикаций и объявлений, ответа на запросы, предотвращения злоупотреблений и повышения безопасности и надежности платформы. Мы не продаем персональные данные, но можем передавать их поставщикам услуг, поддерживающим хостинг, аутентификацию, отправку электронной почты, платежи, хранение или соблюдение закона; данные также могут обрабатываться в нескольких юрисдикциях международного научного общества.</p>","article_title":"СТАТЬЯ 3. Использование, передача и международная обработка"},{"heading":"Срок хранения, безопасность и ваши возможности","body_html":"<p>Мы храним информацию только столько, сколько это разумно необходимо для работы сервиса, выполнения правовых обязанностей, бухгалтерского учета, урегулирования споров и проверки безопасности. Вы можете запросить исправление профиля или задать вопросы о конфиденциальности по адресу <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Хотя StatKISS применяет разумные меры защиты, ни один интернет-сервис не может гарантировать абсолютную безопасность.</p>","article_title":"СТАТЬЯ 4. Срок хранения, безопасность и ваши возможности"}],"effective_date_label":"Дата вступления в силу","last_updated_label":"Последнее обновление","effective_date":"2026-03-28","last_updated":"2026-03-28"},"id":{"slug":"privacy-policy","document_title":"Kebijakan Privasi","document_summary":"Menjelaskan bagaimana StatKISS mengumpulkan, menggunakan, membagikan, menyimpan, dan melindungi informasi pribadi.","document_sections":[{"heading":"Tujuan dan cakupan","body_html":"<p>Kebijakan ini menjelaskan bagaimana StatKISS, yang dioperasikan untuk Korean International Statistical Society (KISS), menangani informasi pribadi dari anggota, penulis, penelaah, donatur, peserta acara, dan pengunjung.</p>","article_title":"PASAL 1. Tujuan dan cakupan"},{"heading":"Data yang kami kumpulkan","body_html":"<p>Kami dapat mengumpulkan data akun dan profil seperti nama, email, afiliasi, jabatan, pilihan keanggotaan, pendaftaran acara, file yang diunggah, dan preferensi komunikasi. Kami juga dapat mengumpulkan data teknis seperti catatan sesi, log keamanan berbasis IP, metadata perangkat atau peramban, dan informasi kunjungan halaman.</p>","article_title":"PASAL 2. Data yang kami kumpulkan"},{"heading":"Penggunaan, pembagian, dan transfer internasional","body_html":"<p>Kami menggunakan informasi untuk mengautentikasi pengguna, mengelola keanggotaan dan acara, mengelola publikasi dan pengumuman, menanggapi permintaan, mencegah penyalahgunaan, serta meningkatkan keamanan dan keandalan platform. Kami tidak menjual informasi pribadi, tetapi dapat membagikannya kepada penyedia layanan yang mendukung hosting, autentikasi, pengiriman email, pembayaran, penyimpanan, atau kepatuhan hukum, dan informasi dapat diproses di beberapa yurisdiksi yang digunakan oleh masyarakat ilmiah internasional.</p>","article_title":"PASAL 3. Penggunaan, pembagian, dan transfer internasional"},{"heading":"Retensi, keamanan, dan pilihan Anda","body_html":"<p>Kami menyimpan informasi hanya selama diperlukan secara wajar untuk operasi layanan, kewajiban hukum, akuntansi, penanganan sengketa, dan peninjauan keamanan. Anda dapat meminta koreksi profil atau mengajukan pertanyaan privasi ke <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Meskipun StatKISS menerapkan perlindungan yang wajar, tidak ada layanan internet yang dapat menjamin keamanan mutlak.</p>","article_title":"PASAL 4. Retensi, keamanan, dan pilihan Anda"}],"effective_date_label":"Tanggal berlaku","last_updated_label":"Pembaruan terakhir","effective_date":"2026-03-28","last_updated":"2026-03-28"},"vi":{"slug":"privacy-policy","document_title":"Chính sách quyền riêng tư","document_summary":"Giải thích cách StatKISS thu thập, sử dụng, chia sẻ, lưu giữ và bảo vệ thông tin cá nhân.","document_sections":[{"heading":"Mục đích và phạm vi","body_html":"<p>Chính sách này giải thích cách StatKISS, được vận hành cho Korean International Statistical Society (KISS), xử lý thông tin cá nhân của hội viên, tác giả, phản biện, nhà tài trợ, người tham dự sự kiện và khách truy cập.</p>","article_title":"ĐIỀU 1. Mục đích và phạm vi"},{"heading":"Dữ liệu chúng tôi thu thập","body_html":"<p>Chúng tôi có thể thu thập dữ liệu tài khoản và hồ sơ như tên, email, cơ quan, chức danh, lựa chọn hội viên, đăng ký sự kiện, tệp tải lên và tùy chọn liên lạc. Chúng tôi cũng có thể thu thập dữ liệu kỹ thuật như bản ghi phiên, nhật ký bảo mật dựa trên IP, siêu dữ liệu thiết bị hoặc trình duyệt và thông tin truy cập trang.</p>","article_title":"ĐIỀU 2. Dữ liệu chúng tôi thu thập"},{"heading":"Sử dụng, chia sẻ và chuyển dữ liệu quốc tế","body_html":"<p>Chúng tôi sử dụng thông tin để xác thực người dùng, vận hành hội viên và sự kiện, quản lý ấn phẩm và thông báo, phản hồi yêu cầu, ngăn chặn lạm dụng và nâng cao tính an toàn, độ tin cậy của nền tảng. Chúng tôi không bán thông tin cá nhân, nhưng có thể chia sẻ với các nhà cung cấp dịch vụ hỗ trợ lưu trữ, xác thực, gửi email, thanh toán, lưu trữ hoặc tuân thủ pháp luật; thông tin cũng có thể được xử lý tại nhiều khu vực tài phán của một hội khoa học quốc tế.</p>","article_title":"ĐIỀU 3. Sử dụng, chia sẻ và chuyển dữ liệu quốc tế"},{"heading":"Lưu giữ, bảo mật và lựa chọn của bạn","body_html":"<p>Chúng tôi chỉ lưu giữ thông tin trong thời gian hợp lý cần thiết cho vận hành dịch vụ, nghĩa vụ pháp lý, kế toán, giải quyết tranh chấp và rà soát bảo mật. Bạn có thể yêu cầu chỉnh sửa hồ sơ hoặc gửi câu hỏi về quyền riêng tư tới <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Mặc dù StatKISS áp dụng các biện pháp bảo vệ hợp lý, không có dịch vụ internet nào có thể bảo đảm an toàn tuyệt đối.</p>","article_title":"ĐIỀU 4. Lưu giữ, bảo mật và lựa chọn của bạn"}],"effective_date_label":"Ngày có hiệu lực","last_updated_label":"Cập nhật lần cuối","effective_date":"2026-03-28","last_updated":"2026-03-28"},"th":{"slug":"privacy-policy","document_title":"นโยบายความเป็นส่วนตัว","document_summary":"อธิบายว่า StatKISS เก็บ ใช้ แบ่งปัน เก็บรักษา และคุ้มครองข้อมูลส่วนบุคคลอย่างไร","document_sections":[{"heading":"วัตถุประสงค์และขอบเขต","body_html":"<p>นโยบายนี้อธิบายว่า StatKISS ซึ่งดำเนินงานเพื่อ Korean International Statistical Society (KISS) จัดการข้อมูลส่วนบุคคลของสมาชิก ผู้เขียน ผู้ประเมิน ผู้บริจาค ผู้เข้าร่วมกิจกรรม และผู้เยี่ยมชมอย่างไร</p>","article_title":"ข้อ 1. วัตถุประสงค์และขอบเขต"},{"heading":"ข้อมูลที่เราเก็บรวบรวม","body_html":"<p>เราอาจเก็บข้อมูลบัญชีและโปรไฟล์ เช่น ชื่อ อีเมล สังกัด ตำแหน่ง ตัวเลือกสมาชิก การลงทะเบียนกิจกรรม ไฟล์ที่อัปโหลด และการตั้งค่าการสื่อสาร นอกจากนี้เราอาจเก็บข้อมูลทางเทคนิค เช่น บันทึกเซสชัน บันทึกความปลอดภัยตาม IP เมทาดาทาของอุปกรณ์หรือเบราว์เซอร์ และข้อมูลการเข้าชมหน้าเว็บ</p>","article_title":"ข้อ 2. ข้อมูลที่เราเก็บรวบรวม"},{"heading":"การใช้ การแบ่งปัน และการโอนข้อมูลระหว่างประเทศ","body_html":"<p>เราใช้ข้อมูลเพื่อยืนยันตัวตนผู้ใช้ ดำเนินงานด้านสมาชิกและกิจกรรม จัดการสิ่งพิมพ์และประกาศ ตอบคำขอ ป้องกันการใช้งานในทางที่ผิด และปรับปรุงความปลอดภัยกับความน่าเชื่อถือของแพลตฟอร์ม เราไม่ขายข้อมูลส่วนบุคคล แต่เราอาจแบ่งปันกับผู้ให้บริการที่สนับสนุนการโฮสต์ การยืนยันตัวตน การส่งอีเมล การชำระเงิน การจัดเก็บ หรือการปฏิบัติตามกฎหมาย และข้อมูลอาจถูกประมวลผลในหลายเขตอำนาจตามธรรมชาติของสมาคมวิชาการนานาชาติ</p>","article_title":"ข้อ 3. การใช้ การแบ่งปัน และการโอนข้อมูลระหว่างประเทศ"},{"heading":"การเก็บรักษา ความปลอดภัย และทางเลือกของคุณ","body_html":"<p>เราเก็บข้อมูลไว้เท่าที่จำเป็นอย่างสมเหตุสมผลสำหรับการดำเนินงานของบริการ ภาระผูกพันทางกฎหมาย การบัญชี การจัดการข้อพิพาท และการทบทวนด้านความปลอดภัย คุณสามารถขอแก้ไขโปรไฟล์หรือสอบถามเรื่องความเป็นส่วนตัวได้ที่ <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a> แม้ว่า StatKISS จะใช้มาตรการป้องกันที่เหมาะสม แต่ไม่มีบริการอินเทอร์เน็ตใดรับประกันความปลอดภัยได้อย่างสมบูรณ์</p>","article_title":"ข้อ 4. การเก็บรักษา ความปลอดภัย และทางเลือกของคุณ"}],"effective_date_label":"วันที่มีผลบังคับใช้","last_updated_label":"อัปเดตล่าสุด","effective_date":"2026-03-28","last_updated":"2026-03-28"},"ms":{"slug":"privacy-policy","document_title":"Dasar Privasi","document_summary":"Menerangkan bagaimana StatKISS mengumpul, menggunakan, berkongsi, menyimpan dan melindungi maklumat peribadi.","document_sections":[{"heading":"Tujuan dan skop","body_html":"<p>Dasar ini menerangkan bagaimana StatKISS, yang dikendalikan untuk Korean International Statistical Society (KISS), mengurus maklumat peribadi ahli, penulis, penilai, penderma, peserta acara dan pelawat.</p>","article_title":"PERKARA 1. Tujuan dan skop"},{"heading":"Data yang kami kumpul","body_html":"<p>Kami mungkin mengumpul data akaun dan profil seperti nama, e-mel, gabungan institusi, jawatan, pilihan keahlian, pendaftaran acara, fail yang dimuat naik dan keutamaan komunikasi. Kami juga mungkin mengumpul data teknikal seperti rekod sesi, log keselamatan berasaskan IP, metadata peranti atau pelayar, dan maklumat lawatan halaman.</p>","article_title":"PERKARA 2. Data yang kami kumpul"},{"heading":"Penggunaan, perkongsian dan pemindahan antarabangsa","body_html":"<p>Kami menggunakan maklumat untuk mengesahkan pengguna, mengurus keahlian dan acara, mentadbir penerbitan dan pengumuman, menjawab permintaan, mencegah penyalahgunaan serta meningkatkan keselamatan dan kebolehpercayaan platform. Kami tidak menjual maklumat peribadi, tetapi kami mungkin berkongsi dengan penyedia perkhidmatan yang menyokong pengehosan, pengesahan, penghantaran e-mel, pembayaran, penyimpanan atau pematuhan undang-undang, dan maklumat boleh diproses di beberapa bidang kuasa yang digunakan oleh persatuan ilmiah antarabangsa.</p>","article_title":"PERKARA 3. Penggunaan, perkongsian dan pemindahan antarabangsa"},{"heading":"Penyimpanan, keselamatan dan pilihan anda","body_html":"<p>Kami menyimpan maklumat hanya selama yang munasabah diperlukan untuk operasi perkhidmatan, kewajipan undang-undang, perakaunan, penyelesaian pertikaian dan semakan keselamatan. Anda boleh meminta pembetulan profil atau mengemukakan soalan privasi ke <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Walaupun StatKISS menggunakan perlindungan yang munasabah, tiada perkhidmatan internet dapat menjamin keselamatan mutlak.</p>","article_title":"PERKARA 4. Penyimpanan, keselamatan dan pilihan anda"}],"effective_date_label":"Tarikh berkuat kuasa","last_updated_label":"Kemas kini terakhir","effective_date":"2026-03-28","last_updated":"2026-03-28"},"fil":{"slug":"privacy-policy","document_title":"Patakaran sa Privacy","document_summary":"Ipinapaliwanag kung paano kinokolekta, ginagamit, ibinabahagi, iniingatan at pinoprotektahan ng StatKISS ang personal na impormasyon.","document_sections":[{"heading":"Layunin at saklaw","body_html":"<p>Ipinapaliwanag ng patakarang ito kung paano pinangangasiwaan ng StatKISS, na pinapatakbo para sa Korean International Statistical Society (KISS), ang personal na impormasyon ng mga miyembro, may-akda, reviewer, donor, kalahok sa event, at bisita.</p>","article_title":"ARTIKULO 1. Layunin at saklaw"},{"heading":"Mga datos na kinokolekta namin","body_html":"<p>Maaaring mangolekta kami ng account at profile data gaya ng pangalan, email, afiliyasyon, titulo, mga pagpili sa membership, pagpaparehistro sa event, mga na-upload na file, at mga kagustuhan sa komunikasyon. Maaari rin kaming mangolekta ng teknikal na datos gaya ng session records, IP-based security logs, device o browser metadata, at impormasyon sa pagbisita sa pahina.</p>","article_title":"ARTIKULO 2. Mga datos na kinokolekta namin"},{"heading":"Paggamit, pagbabahagi, at internasyonal na paglilipat","body_html":"<p>Ginagamit namin ang impormasyon upang patotohanan ang mga user, patakbuhin ang membership at mga event, pamahalaan ang mga publikasyon at anunsyo, tumugon sa mga kahilingan, pigilan ang pang-aabuso, at pahusayin ang seguridad at pagiging maaasahan ng platform. Hindi kami nagbebenta ng personal na impormasyon, ngunit maaari namin itong ibahagi sa mga service provider na sumusuporta sa hosting, authentication, email delivery, payments, storage, o legal compliance, at maaaring iproseso ang impormasyon sa maraming hurisdiksiyong ginagamit ng isang internasyonal na samahang pang-iskolar.</p>","article_title":"ARTIKULO 3. Paggamit, pagbabahagi, at internasyonal na paglilipat"},{"heading":"Pagpapanatili, seguridad, at inyong mga pagpipilian","body_html":"<p>Iniingatan namin ang impormasyon hangga’t makatuwirang kinakailangan para sa operasyon ng serbisyo, mga obligasyong legal, accounting, paghawak ng alitan, at pagsusuri sa seguridad. Maaari kayong humiling ng pagwawasto ng profile o magtanong tungkol sa privacy sa <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Bagama’t gumagamit ang StatKISS ng makatuwirang proteksiyon, walang serbisyong internet ang makapagagarantiya ng ganap na seguridad.</p>","article_title":"ARTIKULO 4. Pagpapanatili, seguridad, at inyong mga pagpipilian"}],"effective_date_label":"Petsa ng bisa","last_updated_label":"Huling na-update","effective_date":"2026-03-28","last_updated":"2026-03-28"},"hi":{"slug":"privacy-policy","document_title":"गोपनीयता नीति","document_summary":"यह बताती है कि StatKISS व्यक्तिगत जानकारी को कैसे एकत्र, उपयोग, साझा, सुरक्षित और संग्रहीत करता है।","document_sections":[{"heading":"उद्देश्य और दायरा","body_html":"<p>यह नीति बताती है कि Korean International Statistical Society (KISS) के लिए संचालित StatKISS, सदस्यों, लेखकों, समीक्षकों, दाताओं, कार्यक्रम प्रतिभागियों और आगंतुकों की व्यक्तिगत जानकारी को कैसे संभालता है।</p>","article_title":"अनुच्छेद 1. उद्देश्य और दायरा"},{"heading":"हम कौन-सा डेटा एकत्र करते हैं","body_html":"<p>हम नाम, ईमेल, संबद्धता, पद, सदस्यता विकल्प, कार्यक्रम पंजीकरण, अपलोड की गई फाइलें और संचार वरीयताओं जैसे खाता और प्रोफ़ाइल डेटा एकत्र कर सकते हैं। हम सत्र रिकॉर्ड, IP-आधारित सुरक्षा लॉग, डिवाइस या ब्राउज़र मेटाडेटा और पृष्ठ भ्रमण जानकारी जैसे तकनीकी डेटा भी एकत्र कर सकते हैं।</p>","article_title":"अनुच्छेद 2. हम कौन-सा डेटा एकत्र करते हैं"},{"heading":"उपयोग, साझा करना और अंतरराष्ट्रीय स्थानांतरण","body_html":"<p>हम जानकारी का उपयोग उपयोगकर्ताओं की पहचान सत्यापित करने, सदस्यता और कार्यक्रम चलाने, प्रकाशनों और घोषणाओं का प्रबंधन करने, अनुरोधों का उत्तर देने, दुरुपयोग रोकने और मंच की सुरक्षा व विश्वसनीयता सुधारने के लिए करते हैं। हम व्यक्तिगत जानकारी नहीं बेचते, लेकिन होस्टिंग, प्रमाणीकरण, ईमेल वितरण, भुगतान, भंडारण या कानूनी अनुपालन का समर्थन करने वाले सेवा प्रदाताओं के साथ आवश्यक सीमा तक जानकारी साझा कर सकते हैं, और यह जानकारी एक अंतरराष्ट्रीय शैक्षणिक संस्था से संबंधित विभिन्न न्यायक्षेत्रों में संसाधित हो सकती है।</p>","article_title":"अनुच्छेद 3. उपयोग, साझा करना और अंतरराष्ट्रीय स्थानांतरण"},{"heading":"संग्रहण, सुरक्षा और आपके विकल्प","body_html":"<p>हम जानकारी को केवल उतनी अवधि तक रखते हैं जितनी सेवा संचालन, कानूनी दायित्व, लेखांकन, विवाद निपटान और सुरक्षा समीक्षा के लिए उचित रूप से आवश्यक है। आप प्रोफ़ाइल सुधार का अनुरोध कर सकते हैं या गोपनीयता संबंधी प्रश्न <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a> पर भेज सकते हैं। यद्यपि StatKISS उचित सुरक्षा उपाय लागू करता है, कोई भी इंटरनेट सेवा पूर्ण सुरक्षा की गारंटी नहीं दे सकती।</p>","article_title":"अनुच्छेद 4. संग्रहण, सुरक्षा और आपके विकल्प"}],"effective_date_label":"प्रभावी तिथि","last_updated_label":"अंतिम अपडेट","effective_date":"2026-03-28","last_updated":"2026-03-28"},"ar":{"slug":"privacy-policy","document_title":"سياسة الخصوصية","document_summary":"توضح كيف يجمع StatKISS المعلومات الشخصية ويستخدمها ويشاركها ويحتفظ بها ويحميها.","document_sections":[{"heading":"الغرض ونطاق التطبيق","body_html":"<p>توضح هذه السياسة كيف يتعامل StatKISS، الذي يُدار لصالح Korean International Statistical Society (KISS)، مع المعلومات الشخصية الخاصة بالأعضاء والمؤلفين والمراجعين والمتبرعين والمشاركين في الفعاليات والزوار.</p>","article_title":"المادة 1. الغرض ونطاق التطبيق"},{"heading":"البيانات التي نجمعها","body_html":"<p>قد نجمع بيانات الحساب والملف الشخصي مثل الاسم والبريد الإلكتروني والانتماء الوظيفي والمسمى المهني وخيارات العضوية وتسجيلات الفعاليات والملفات المرفوعة وتفضيلات التواصل. وقد نجمع أيضا بيانات تقنية مثل سجلات الجلسات وسجلات الأمان المعتمدة على عنوان IP وبيانات الجهاز أو المتصفح ومعلومات زيارة الصفحات.</p>","article_title":"المادة 2. البيانات التي نجمعها"},{"heading":"الاستخدام والمشاركة والنقل الدولي","body_html":"<p>نستخدم المعلومات للتحقق من هوية المستخدمين وتشغيل العضويات والفعاليات وإدارة المنشورات والإعلانات والرد على الطلبات ومنع إساءة الاستخدام وتحسين أمان المنصة وموثوقيتها. نحن لا نبيع المعلومات الشخصية، لكن قد نشاركها مع مقدمي الخدمات الذين يدعمون الاستضافة أو المصادقة أو إرسال البريد الإلكتروني أو المدفوعات أو التخزين أو الامتثال القانوني، وقد تُعالج المعلومات في عدة ولايات قضائية مرتبطة بجمعية علمية دولية.</p>","article_title":"المادة 3. الاستخدام والمشاركة والنقل الدولي"},{"heading":"الاحتفاظ والأمان وخياراتك","body_html":"<p>نحتفظ بالمعلومات فقط للمدة اللازمة بشكل معقول لتشغيل الخدمة والالتزامات القانونية والمحاسبة ومعالجة النزاعات ومراجعة الأمان. يمكنك طلب تصحيح ملفك الشخصي أو إرسال أسئلة الخصوصية إلى <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. وعلى الرغم من أن StatKISS يطبق وسائل حماية معقولة، فلا يمكن لأي خدمة إنترنت أن تضمن أمانا مطلقا.</p>","article_title":"المادة 4. الاحتفاظ والأمان وخياراتك"}],"effective_date_label":"تاريخ السريان","last_updated_label":"آخر تحديث","effective_date":"2026-03-28","last_updated":"2026-03-28"},"it":{"slug":"privacy-policy","document_title":"Informativa sulla privacy","document_summary":"Spiega come StatKISS raccoglie, utilizza, condivide, conserva e protegge le informazioni personali.","document_sections":[{"heading":"Finalità e ambito","body_html":"<p>Questa informativa spiega come StatKISS, gestito per la Korean International Statistical Society (KISS), tratta le informazioni personali di membri, autori, revisori, donatori, partecipanti agli eventi e visitatori.</p>","article_title":"ARTICOLO 1. Finalità e ambito"},{"heading":"Dati che raccogliamo","body_html":"<p>Possiamo raccogliere dati di account e profilo come nome, e-mail, affiliazione, ruolo professionale, scelte di membership, registrazioni agli eventi, file caricati e preferenze di comunicazione. Possiamo inoltre raccogliere dati tecnici come registri di sessione, log di sicurezza basati su IP, metadati del dispositivo o del browser e informazioni sulle visite alle pagine.</p>","article_title":"ARTICOLO 2. Dati che raccogliamo"},{"heading":"Uso, condivisione e trasferimenti internazionali","body_html":"<p>Utilizziamo le informazioni per autenticare gli utenti, gestire membership ed eventi, amministrare pubblicazioni e annunci, rispondere alle richieste, prevenire abusi e migliorare la sicurezza e l’affidabilità della piattaforma. Non vendiamo informazioni personali, ma possiamo condividerle con fornitori che supportano hosting, autenticazione, invio di e-mail, pagamenti, archiviazione o conformità legale; le informazioni possono inoltre essere trattate in più giurisdizioni utilizzate da una società accademica internazionale.</p>","article_title":"ARTICOLO 3. Uso, condivisione e trasferimenti internazionali"},{"heading":"Conservazione, sicurezza e vostre scelte","body_html":"<p>Conserviamo le informazioni solo per il tempo ragionevolmente necessario al funzionamento del servizio, agli obblighi legali, alla contabilità, alla gestione delle controversie e alla revisione della sicurezza. Potete richiedere correzioni del profilo o porre domande sulla privacy a <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Sebbene StatKISS applichi misure di protezione ragionevoli, nessun servizio internet può garantire una sicurezza assoluta.</p>","article_title":"ARTICOLO 4. Conservazione, sicurezza e vostre scelte"}],"effective_date_label":"Data di entrata in vigore","last_updated_label":"Ultimo aggiornamento","effective_date":"2026-03-28","last_updated":"2026-03-28"},"nl":{"slug":"privacy-policy","document_title":"Privacybeleid","document_summary":"Legt uit hoe StatKISS persoonlijke informatie verzamelt, gebruikt, deelt, bewaart en beschermt.","document_sections":[{"heading":"Doel en reikwijdte","body_html":"<p>Dit beleid legt uit hoe StatKISS, dat wordt beheerd voor de Korean International Statistical Society (KISS), persoonlijke informatie van leden, auteurs, reviewers, donateurs, deelnemers aan evenementen en bezoekers verwerkt.</p>","article_title":"ARTIKEL 1. Doel en reikwijdte"},{"heading":"Gegevens die wij verzamelen","body_html":"<p>Wij kunnen account- en profielgegevens verzamelen zoals naam, e-mailadres, affiliatie, functie, keuzes voor membership, evenementregistraties, geüploade bestanden en communicatievoorkeuren. Wij kunnen ook technische gegevens verzamelen zoals sessieregistraties, IP-gebaseerde beveiligingslogs, metadata van apparaat of browser en informatie over paginabezoeken.</p>","article_title":"ARTIKEL 2. Gegevens die wij verzamelen"},{"heading":"Gebruik, delen en internationale overdrachten","body_html":"<p>Wij gebruiken informatie om gebruikers te authenticeren, memberships en evenementen te beheren, publicaties en aankondigingen te administreren, verzoeken te beantwoorden, misbruik te voorkomen en de veiligheid en betrouwbaarheid van het platform te verbeteren. Wij verkopen geen persoonlijke informatie, maar kunnen die delen met dienstverleners voor hosting, authenticatie, e-mailverzending, betalingen, opslag of naleving van wetgeving; informatie kan ook in meerdere rechtsgebieden worden verwerkt die door een internationale wetenschappelijke vereniging worden gebruikt.</p>","article_title":"ARTIKEL 3. Gebruik, delen en internationale overdrachten"},{"heading":"Bewaring, beveiliging en uw keuzes","body_html":"<p>Wij bewaren informatie alleen zolang dat redelijkerwijs nodig is voor de werking van de dienst, wettelijke verplichtingen, boekhouding, geschilafhandeling en beveiligingscontrole. U kunt profielcorrecties aanvragen of privacyvragen sturen naar <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Hoewel StatKISS redelijke beveiligingsmaatregelen toepast, kan geen enkele internetdienst absolute veiligheid garanderen.</p>","article_title":"ARTIKEL 4. Bewaring, beveiliging en uw keuzes"}],"effective_date_label":"Ingangsdatum","last_updated_label":"Laatst bijgewerkt","effective_date":"2026-03-28","last_updated":"2026-03-28"},"pl":{"slug":"privacy-policy","document_title":"Polityka prywatności","document_summary":"Wyjaśnia, w jaki sposób StatKISS gromadzi, wykorzystuje, udostępnia, przechowuje i chroni dane osobowe.","document_sections":[{"heading":"Cel i zakres","body_html":"<p>Niniejsza polityka wyjaśnia, w jaki sposób StatKISS, prowadzony dla Korean International Statistical Society (KISS), przetwarza dane osobowe członków, autorów, recenzentów, darczyńców, uczestników wydarzeń i odwiedzających.</p>","article_title":"ARTYKUŁ 1. Cel i zakres"},{"heading":"Jakie dane zbieramy","body_html":"<p>Możemy gromadzić dane konta i profilu, takie jak imię i nazwisko, adres e-mail, afiliacja, stanowisko, wybory członkowskie, rejestracje na wydarzenia, przesłane pliki i preferencje komunikacyjne. Możemy także gromadzić dane techniczne, takie jak rejestry sesji, logi bezpieczeństwa oparte na IP, metadane urządzenia lub przeglądarki oraz informacje o odwiedzanych stronach.</p>","article_title":"ARTYKUŁ 2. Jakie dane zbieramy"},{"heading":"Wykorzystanie, udostępnianie i transfery międzynarodowe","body_html":"<p>Wykorzystujemy informacje do uwierzytelniania użytkowników, obsługi członkostwa i wydarzeń, administrowania publikacjami i ogłoszeniami, odpowiadania na zapytania, zapobiegania nadużyciom oraz poprawy bezpieczeństwa i niezawodności platformy. Nie sprzedajemy danych osobowych, ale możemy udostępniać je usługodawcom wspierającym hosting, uwierzytelnianie, wysyłkę e-maili, płatności, przechowywanie lub zgodność z prawem; informacje mogą być także przetwarzane w wielu jurysdykcjach używanych przez międzynarodowe stowarzyszenie naukowe.</p>","article_title":"ARTYKUŁ 3. Wykorzystanie, udostępnianie i transfery międzynarodowe"},{"heading":"Przechowywanie, bezpieczeństwo i Twoje wybory","body_html":"<p>Przechowujemy informacje tylko tak długo, jak jest to rozsądnie konieczne do działania usługi, wypełnienia obowiązków prawnych, prowadzenia księgowości, rozstrzygania sporów i przeglądu bezpieczeństwa. Możesz poprosić o korektę profilu lub przesłać pytania dotyczące prywatności na adres <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Chociaż StatKISS stosuje rozsądne zabezpieczenia, żadna usługa internetowa nie może zagwarantować całkowitego bezpieczeństwa.</p>","article_title":"ARTYKUŁ 4. Przechowywanie, bezpieczeństwo i Twoje wybory"}],"effective_date_label":"Data wejścia w życie","last_updated_label":"Ostatnia aktualizacja","effective_date":"2026-03-28","last_updated":"2026-03-28"},"sv":{"slug":"privacy-policy","document_title":"Integritetspolicy","document_summary":"Förklarar hur StatKISS samlar in, använder, delar, lagrar och skyddar personuppgifter.","document_sections":[{"heading":"Syfte och omfattning","body_html":"<p>Denna policy förklarar hur StatKISS, som drivs för Korean International Statistical Society (KISS), behandlar personuppgifter om medlemmar, författare, granskare, givare, deltagare i evenemang och besökare.</p>","article_title":"ARTIKEL 1. Syfte och omfattning"},{"heading":"Vilka uppgifter vi samlar in","body_html":"<p>Vi kan samla in konto- och profiluppgifter såsom namn, e-postadress, tillhörighet, titel, medlemsval, evenemangsregistreringar, uppladdade filer och kommunikationspreferenser. Vi kan också samla in tekniska uppgifter såsom sessionsloggar, IP-baserade säkerhetsloggar, metadata om enhet eller webbläsare och information om sidbesök.</p>","article_title":"ARTIKEL 2. Vilka uppgifter vi samlar in"},{"heading":"Användning, delning och internationella överföringar","body_html":"<p>Vi använder information för att autentisera användare, driva medlemskap och evenemang, administrera publikationer och meddelanden, besvara förfrågningar, förebygga missbruk och förbättra plattformens säkerhet och tillförlitlighet. Vi säljer inte personuppgifter, men vi kan dela dem med tjänsteleverantörer som stöder hosting, autentisering, e-postutskick, betalningar, lagring eller rättslig efterlevnad; information kan också behandlas i flera jurisdiktioner som används av ett internationellt vetenskapligt sällskap.</p>","article_title":"ARTIKEL 3. Användning, delning och internationella överföringar"},{"heading":"Lagring, säkerhet och dina val","body_html":"<p>Vi behåller information endast så länge det rimligen behövs för tjänstens drift, rättsliga skyldigheter, bokföring, tvistlösning och säkerhetsgranskning. Du kan begära profilkorrigeringar eller ställa integritetsfrågor till <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Även om StatKISS tillämpar rimliga skyddsåtgärder kan ingen internettjänst garantera absolut säkerhet.</p>","article_title":"ARTIKEL 4. Lagring, säkerhet och dina val"}],"effective_date_label":"Ikraftträdandedatum","last_updated_label":"Senast uppdaterad","effective_date":"2026-03-28","last_updated":"2026-03-28"},"tr":{"slug":"privacy-policy","document_title":"Gizlilik Politikası","document_summary":"StatKISS’in kişisel bilgileri nasıl topladığını, kullandığını, paylaştığını, sakladığını ve koruduğunu açıklar.","document_sections":[{"heading":"Amaç ve kapsam","body_html":"<p>Bu politika, Korean International Statistical Society (KISS) için işletilen StatKISS’in üyelerin, yazarların, hakemlerin, bağışçıların, etkinlik katılımcılarının ve ziyaretçilerin kişisel bilgilerini nasıl işlediğini açıklar.</p>","article_title":"MADDE 1. Amaç ve kapsam"},{"heading":"Topladığımız veriler","body_html":"<p>Ad, e-posta adresi, kurum, unvan, üyelik seçimleri, etkinlik kayıtları, yüklenen dosyalar ve iletişim tercihleri gibi hesap ve profil verilerini toplayabiliriz. Ayrıca oturum kayıtları, IP tabanlı güvenlik günlükleri, cihaz veya tarayıcı meta verileri ve sayfa ziyaret bilgileri gibi teknik verileri de toplayabiliriz.</p>","article_title":"MADDE 2. Topladığımız veriler"},{"heading":"Kullanım, paylaşım ve uluslararası aktarımlar","body_html":"<p>Bilgileri kullanıcıları doğrulamak, üyelik ve etkinlikleri yürütmek, yayınları ve duyuruları yönetmek, talepleri yanıtlamak, kötüye kullanımı önlemek ve platformun güvenliğini ve güvenilirliğini artırmak için kullanırız. Kişisel bilgileri satmayız; ancak barındırma, kimlik doğrulama, e-posta gönderimi, ödeme, depolama veya yasal uyum hizmetlerini destekleyen sağlayıcılarla gerekli ölçüde paylaşabiliriz. Bilgiler ayrıca uluslararası bir akademik derneğin kullandığı birden çok yargı alanında işlenebilir.</p>","article_title":"MADDE 3. Kullanım, paylaşım ve uluslararası aktarımlar"},{"heading":"Saklama, güvenlik ve seçenekleriniz","body_html":"<p>Bilgileri yalnızca hizmetin işletilmesi, yasal yükümlülükler, muhasebe, uyuşmazlık çözümü ve güvenlik incelemesi için makul ölçüde gerekli olduğu sürece saklarız. Profil düzeltmesi talep edebilir veya gizlilik sorularınızı <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a> adresine gönderebilirsiniz. StatKISS makul koruma önlemleri uygular; ancak hiçbir internet hizmeti mutlak güvenlik garanti edemez.</p>","article_title":"MADDE 4. Saklama, güvenlik ve seçenekleriniz"}],"effective_date_label":"Yürürlük tarihi","last_updated_label":"Son güncelleme","effective_date":"2026-03-28","last_updated":"2026-03-28"},"uk":{"slug":"privacy-policy","document_title":"Політика конфіденційності","document_summary":"Пояснює, як StatKISS збирає, використовує, передає, зберігає та захищає персональні дані.","document_sections":[{"heading":"Мета та сфера дії","body_html":"<p>Ця політика пояснює, як StatKISS, що працює для Korean International Statistical Society (KISS), обробляє персональні дані членів товариства, авторів, рецензентів, донорів, учасників подій і відвідувачів.</p>","article_title":"СТАТТЯ 1. Мета та сфера дії"},{"heading":"Які дані ми збираємо","body_html":"<p>Ми можемо збирати дані облікового запису та профілю, зокрема ім’я, електронну адресу, афіліацію, посаду, вибір членства, реєстрації на події, завантажені файли та налаштування комунікації. Ми також можемо збирати технічні дані, такі як записи сеансів, журнали безпеки на основі IP, метадані пристрою або браузера та відомості про відвідування сторінок.</p>","article_title":"СТАТТЯ 2. Які дані ми збираємо"},{"heading":"Використання, передача та міжнародна обробка","body_html":"<p>Ми використовуємо інформацію для автентифікації користувачів, керування членством і подіями, адміністрування публікацій і оголошень, відповіді на запити, запобігання зловживанням і підвищення безпеки та надійності платформи. Ми не продаємо персональні дані, але можемо передавати їх постачальникам послуг, які підтримують хостинг, автентифікацію, надсилання електронної пошти, платежі, зберігання або дотримання законодавства; дані також можуть оброблятися в кількох юрисдикціях міжнародного наукового товариства.</p>","article_title":"СТАТТЯ 3. Використання, передача та міжнародна обробка"},{"heading":"Зберігання, безпека та ваш вибір","body_html":"<p>Ми зберігаємо інформацію лише стільки, скільки це розумно необхідно для роботи сервісу, виконання правових обов’язків, бухгалтерського обліку, врегулювання спорів і перевірки безпеки. Ви можете подати запит на виправлення профілю або поставити запитання щодо конфіденційності на адресу <a href=\"mailto:info@statkiss.org\">info@statkiss.org</a>. Хоча StatKISS застосовує розумні заходи захисту, жоден інтернет-сервіс не може гарантувати абсолютну безпеку.</p>","article_title":"СТАТТЯ 4. Зберігання, безпека та ваш вибір"}],"effective_date_label":"Дата набрання чинності","last_updated_label":"Останнє оновлення","effective_date":"2026-03-28","last_updated":"2026-03-28"}};

function resolveLang(raw) {
  const H = window.StatKISS_I18N;
  if (H && typeof H.resolveLangCode === 'function') {
    return H.resolveLangCode(raw || 'en');
  }
  return String(raw || 'en').trim() || 'en';
}

function getDocument(lang) {
  const code = resolveLang(lang);
  return DOCUMENTS[code] || DOCUMENTS.en || {};
}

window[NAMESPACE] = {
  slug: SLUG,
  languages: SUPPORTED_LANGS,
  resolveLang,
  getDocument,
};
window.dispatchEvent(new CustomEvent('statkiss:i18nReady', { detail: { namespace: SLUG } }));
})();
